  ('bookkeeper-moex-01602', 'bookkeeper', 'bookkeeper-moex-101-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '寶麗公司在X1年1月1日與12月31日之保留盈餘分別為$41,000與$58,000，X1年間公司之收益總額 為$52,000，費損總額為$23,500。在沒有其他事件的情況下，寶麗公司X1年之股利為：', '["$70,500", "$28,500", "$17,000", "$11,500"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "0b4a899ddb2e", "answer_pdf_sha1": "b9d700b25f96", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01603', 'bookkeeper', 'bookkeeper-moex-101-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '中山公司 X9 年期初存貨$5,000，進貨$35,000，期末存貨$11,000，現金銷貨$5,000，銷貨毛利$11,000，期 初應收帳款$8,000，收回應收帳款$26,000，則期末之應收帳款餘額為：', '["$22,000", "$43,000", "$25,000", "$17,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "0b4a899ddb2e", "answer_pdf_sha1": "b9d700b25f96", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01604', 'bookkeeper', 'bookkeeper-moex-101-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '豆枝公司在X1年出售大華公司股票獲得現金$120,000，並向豐豐銀行借款$50,000，其後處分大直的一塊 土地獲得現金$18,000，此外，以現金$27,000購入小星公司股票300張，並以$20,000現金購回庫藏股。 請計算豆枝公司X1年之投資活動現金流量：', '["$111,000", "$123,000", "$141,000", "$161,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "0b4a899ddb2e", "answer_pdf_sha1": "b9d700b25f96", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
