  ('bookkeeper-moex-01606', 'bookkeeper', 'bookkeeper-moex-101-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '幕亮公司期末存貨為$80,000，進貨為$120,000，銷貨成本為$100,000，試問，幕亮公司期初存貨為：', '["$60,000", "$100,000", "$120,000", "$140,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "0b4a899ddb2e", "answer_pdf_sha1": "b9d700b25f96", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
